code = """import json
import pandas as pd

# Load papers data from previous step
papers_data = locals()['var_functions.execute_python:8']

# Extract titles from papers data
paper_titles = [paper['title'] for paper in papers_data if 'title' in paper]

# Load citations data from file
citations_file_path = locals()['var_functions.query_db:5']

with open(citations_file_path, 'r') as f:
    citations_data = json.load(f)

# Create a DataFrame for easier processing
citations_df = pd.DataFrame(citations_data)

# Filter for papers from 2016 physical activity domain
filtered_citations = citations_df[citations_df['title'].isin(paper_titles)]

# Group by title and sum citation counts
paper_citations = filtered_citations.groupby('title', as_index=False).agg({
    'total_citations': 'first'  # Since total_citations is already summed per title
})

# Convert to list of dicts
result_data = paper_citations.to_dict('records')

# Print result
print('__RESULT__:')
print(json.dumps(result_data, indent=2))"""

